:root {
  --bg: #f5f7fb;
  --paper: #ffffff;
  --ink: #111827;
  --muted: #667085;
  --line: #e5e7eb;
  --soft: #f9fafb;
  --brand: #8a5a00;
  --brand-2: #c08400;
  --brand-soft: #fff6df;
  --green: #067647;
  --red: #b42318;
  --blue: #175cd3;
  --shadow: 0 18px 50px rgba(16, 24, 40, 0.12);
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  background: var(--bg);
  color: var(--ink);
  font-family: Inter, Arial, sans-serif;
}

.report-shell {
  padding: 24px;
}

.report-paper {
  max-width: 1120px;
  margin: 0 auto;
  background: var(--paper);
  border: 1px solid var(--line);
  border-radius: 12px;
  box-shadow: var(--shadow);
  overflow: hidden;
}

.report-topbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  padding: 16px 22px;
  background: linear-gradient(135deg, #7a4d00, #b87900);
  color: #fff;
}

.brand-block h1 {
  margin: 0;
  font-size: 22px;
  font-weight: 800;
  letter-spacing: 0;
}

.brand-block p {
  margin: 4px 0 0;
  font-size: 12px;
  opacity: 0.88;
}

.actions {
  display: flex;
  gap: 8px;
}

.btn {
  border: 1px solid rgba(255, 255, 255, 0.35);
  background: rgba(255, 255, 255, 0.14);
  color: #fff;
  border-radius: 7px;
  padding: 8px 11px;
  font-size: 12px;
  font-weight: 700;
  cursor: pointer;
}

.btn:hover {
  background: rgba(255, 255, 255, 0.22);
}

.report-body {
  padding: 22px;
}

.header-grid {
  display: grid;
  grid-template-columns: 1.4fr 0.8fr;
  gap: 18px;
  margin-bottom: 18px;
}

.panel {
  border: 1px solid var(--line);
  border-radius: 10px;
  background: #fff;
  overflow: hidden;
}

.panel-head {
  padding: 12px 14px;
  background: var(--soft);
  border-bottom: 1px solid var(--line);
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.panel-title {
  margin: 0;
  font-size: 14px;
  font-weight: 800;
}

.panel-body {
  padding: 14px;
}

.product-title {
  margin: 0 0 4px;
  font-size: 24px;
  font-weight: 850;
}

.product-code {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 5px 8px;
  border-radius: 6px;
  background: var(--brand-soft);
  color: var(--brand);
  font-size: 12px;
  font-weight: 800;
}

.muted {
  color: var(--muted);
  font-size: 12px;
}

.info-list {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 9px 16px;
  margin-top: 14px;
}

.info-item span {
  display: block;
  color: var(--muted);
  font-size: 11px;
  margin-bottom: 2px;
}

.info-item strong {
  font-size: 13px;
}

.kpi-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 10px;
  margin: 18px 0;
}

.kpi {
  border: 1px solid var(--line);
  border-radius: 10px;
  padding: 13px;
  background: #fff;
}

.kpi span {
  display: block;
  color: var(--muted);
  font-size: 11px;
  margin-bottom: 6px;
}

.kpi strong {
  display: block;
  font-size: 19px;
  font-weight: 850;
}

.kpi small {
  display: block;
  margin-top: 4px;
  color: var(--muted);
  font-size: 11px;
}

.section {
  margin-top: 18px;
  break-inside: avoid;
}

.section-head {
  display: flex;
  justify-content: space-between;
  align-items: end;
  gap: 12px;
  margin-bottom: 9px;
}

.section-head h2 {
  margin: 0;
  font-size: 15px;
  font-weight: 850;
}

.section-head p {
  margin: 2px 0 0;
  color: var(--muted);
  font-size: 11px;
}

.table-wrap {
  border: 1px solid var(--line);
  border-radius: 10px;
  overflow: hidden;
  background: #fff;
}

.table {
  width: 100%;
  border-collapse: collapse;
  font-size: 12px;
}

.table th {
  background: var(--soft);
  color: #344054;
  text-align: left;
  padding: 9px;
  border-bottom: 1px solid var(--line);
  font-weight: 800;
  white-space: nowrap;
}

.table td {
  padding: 9px;
  border-bottom: 1px solid var(--line);
  color: #344054;
  vertical-align: top;
}

.table tr:last-child td {
  border-bottom: 0;
}

.num {
  text-align: right;
  font-variant-numeric: tabular-nums;
}

.badge {
  display: inline-flex;
  align-items: center;
  padding: 4px 7px;
  border-radius: 6px;
  font-size: 11px;
  font-weight: 800;
  background: var(--soft);
  color: var(--ink);
}

.badge.ok {
  background: #ecfdf3;
  color: var(--green);
}

.badge.low {
  background: #fef3f2;
  color: var(--red);
}

.badge.info {
  background: #eff8ff;
  color: var(--blue);
}

.empty {
  border: 1px dashed var(--line);
  border-radius: 10px;
  padding: 16px;
  color: var(--muted);
  background: #fafafa;
  font-size: 12px;
}

.two-col {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px;
}

.footer {
  margin-top: 24px;
  padding-top: 14px;
  border-top: 1px solid var(--line);
  color: var(--muted);
  font-size: 11px;
  display: flex;
  justify-content: space-between;
}

@media print {
  body {
    background: #fff;
  }
  .report-shell {
    padding: 0;
  }
  .report-paper {
    border: 0;
    box-shadow: none;
    border-radius: 0;
  }
  .actions {
    display: none;
  }
  .section {
    break-inside: avoid;
  }
}

