function pick(obj, keys, fallback = "") {
  for (const key of keys) {
    if (obj && obj[key] !== undefined && obj[key] !== null && obj[key] !== "") {
      return obj[key];
    }
  }
  return fallback;
}

function text(value, fallback = "-") {
  return value === null || value === undefined || value === "" ? fallback : String(value);
}

function num(value) {
  return Number(value || 0);
}

function money(value) {
  return num(value).toLocaleString("en-US", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });
}

function qty(value) {
  return num(value).toLocaleString("en-US", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 4
  });
}

function list(data, limit) {
  return Array.isArray(data) ? data.slice(0, limit) : [];
}

function table(columns, data, emptyText) {
  if (!data || !data.length) {
    return `<div class="empty">${emptyText}</div>`;
  }

  return `
    <div class="table-wrap">
      <table class="table">
        <thead>
          <tr>
            ${columns.map(col => `<th class="${col.num ? "num" : ""}">${col.label}</th>`).join("")}
          </tr>
        </thead>
        <tbody>
          ${data.map(row => `
            <tr>
              ${columns.map(col => `<td class="${col.num ? "num" : ""}">${col.value(row)}</td>`).join("")}
            </tr>
          `).join("")}
        </tbody>
      </table>
    </div>
  `;
}

function render() {
  const model = appsmith.model || {};
  const company = model.company || {};
  const product = model.product || {};
  const availability = model.availability || [];
  const sales = model.sales || [];
  const purchases = model.purchases || [];
  const movements = model.movements || [];
  const prices = model.prices || [];
  const norm = model.norm || null;
  const normItems = model.normItems || [];
  const imports = model.imports || [];

  const productCode = pick(product, ["productCode", "code", "Code"], "-");
  const productName = pick(product, ["productName", "name", "Name"], "-");
  const productType = pick(product, ["productType", "product_type", "Product Type"], "-");
  const barcode = pick(product, ["barcode", "Barcode"], "-");
  const sku = pick(product, ["sku", "SKU"], "-");
  const unit = pick(product, ["unit", "unitCode", "Unit"], "-");
  const category = pick(product, ["category", "categoryName", "Category"], "-");
  const tax = pick(product, ["taxRate", "tax_rate", "Tax Rate"], "-");

  const totalStock = availability.reduce((sum, row) =>
    sum + num(pick(row, ["quantity_balance", "availableStock", "Available", "available"], 0)), 0
  );

  const lowStockCount = availability.filter(row => {
    const available = num(pick(row, ["quantity_balance", "availableStock", "Available", "available"], 0));
    const minimum = num(pick(row, ["minimum_stock", "MinimumStock", "minimumStock"], 0));
    return minimum > 0 && available < minimum;
  }).length;

  const totalSalesValue = sales.reduce((sum, row) =>
    sum + num(pick(row, ["line_total", "Total", "total", "lineTotal"], 0)), 0
  );

  const totalSalesQty = sales.reduce((sum, row) =>
    sum + num(pick(row, ["quantity", "Quantity"], 0)), 0
  );

  const salePrice = pick(product, ["salePrice", "sale_price", "SalePrice"], 0);
  const purchasePrice = pick(product, ["purchasePrice", "purchase_price", "PurchasePrice"], 0);

  document.getElementById("product-report-root").innerHTML = `
    <div class="report-shell">
      <div class="report-paper">
        <div class="report-topbar">
          <div class="brand-block">
            <h1>${text(company.name, "Axon")}</h1>
            <p>${text(company.address, "")} ${text(company.city, "")} ${company.taxNumber ? " | OIB: " + text(company.taxNumber) : ""}</p>
          </div>
          <div class="actions">
            <button class="btn" onclick="window.print()">Print</button>
          </div>
        </div>

        <div class="report-body">
          <div class="header-grid">
            <div class="panel">
              <div class="panel-head">
                <h2 class="panel-title">Product Report</h2>
                <span class="badge info">${text(model.generatedAt)}</span>
              </div>
              <div class="panel-body">
                <h1 class="product-title">${text(productName)}</h1>
                <span class="product-code">${text(productCode)}</span>
                <p class="muted" style="margin-top:10px">${text(pick(product, ["description", "Description"], "No description"))}</p>

                <div class="info-list">
                  <div class="info-item"><span>Barcode</span><strong>${text(barcode)}</strong></div>
                  <div class="info-item"><span>SKU</span><strong>${text(sku)}</strong></div>
                  <div class="info-item"><span>Type</span><strong>${text(productType)}</strong></div>
                  <div class="info-item"><span>Unit</span><strong>${text(unit)}</strong></div>
                  <div class="info-item"><span>Category</span><strong>${text(category)}</strong></div>
                  <div class="info-item"><span>Tax Rate</span><strong>${text(tax)}</strong></div>
                </div>
              </div>
            </div>

            <div class="panel">
              <div class="panel-head">
                <h2 class="panel-title">Company</h2>
              </div>
              <div class="panel-body">
                <div class="info-list" style="grid-template-columns:1fr">
                  <div class="info-item"><span>Name</span><strong>${text(company.name)}</strong></div>
                  <div class="info-item"><span>Address</span><strong>${text(company.address)} ${text(company.city, "")}</strong></div>
                  <div class="info-item"><span>Email</span><strong>${text(company.email)}</strong></div>
                  <div class="info-item"><span>Phone</span><strong>${text(company.phone)}</strong></div>
                </div>
              </div>
            </div>
          </div>

          <div class="kpi-grid">
            <div class="kpi"><span>Sale Price</span><strong>${money(salePrice)}</strong><small>Current product sale price</small></div>
            <div class="kpi"><span>Purchase Price</span><strong>${money(purchasePrice)}</strong><small>Current product purchase price</small></div>
            <div class="kpi"><span>Total Stock</span><strong>${qty(totalStock)}</strong><small>Across listed warehouses</small></div>
            <div class="kpi"><span>Sales Total</span><strong>${money(totalSalesValue)}</strong><small>${qty(totalSalesQty)} units sold</small></div>
          </div>

          <div class="section">
            <div class="section-head">
              <div>
                <h2>Stock By Warehouse</h2>
                <p>Availability and low stock status by warehouse.</p>
              </div>
              <span class="badge ${lowStockCount ? "low" : "ok"}">${lowStockCount ? lowStockCount + " low" : "OK"}</span>
            </div>
            ${table([
              { label: "Warehouse", value: r => text(pick(r, ["warehouse_name", "Warehouse", "warehouse"], pick(r, ["warehouse_code"], "-"))) },
              { label: "Code", value: r => text(pick(r, ["warehouse_code", "WarehouseCode"], "-")) },
              { label: "Available", num: true, value: r => qty(pick(r, ["quantity_balance", "availableStock", "Available", "available"], 0)) },
              { label: "Minimum", num: true, value: r => qty(pick(r, ["minimum_stock", "minimumStock", "MinimumStock"], 0)) },
              { label: "Status", value: r => {
                const available = num(pick(r, ["quantity_balance", "availableStock", "Available", "available"], 0));
                const minimum = num(pick(r, ["minimum_stock", "minimumStock", "MinimumStock"], 0));
                return minimum > 0 && available < minimum
                  ? `<span class="badge low">LOW</span>`
                  : `<span class="badge ok">OK</span>`;
              }}
            ], list(availability, 30), "No stock availability data.")}
          </div>

          <div class="section">
            <div class="section-head">
              <div>
                <h2>Recent Sales</h2>
                <p>Latest sales lines for this product.</p>
              </div>
            </div>
            ${table([
              { label: "Date", value: r => text(pick(r, ["document_date", "Date", "date"], "-")) },
              { label: "Document", value: r => text(pick(r, ["document_number", "Number", "documentNumber"], "-")) },
              { label: "Customer", value: r => text(pick(r, ["customer", "Customer", "partner_name"], "-")) },
              { label: "Qty", num: true, value: r => qty(pick(r, ["quantity", "Quantity"], 0)) },
              { label: "Total", num: true, value: r => money(pick(r, ["line_total", "Total", "total", "lineTotal"], 0)) }
            ], list(sales, 12), "No recent sales data.")}
          </div>

          <div class="section">
            <div class="section-head">
              <div>
                <h2>Stock Movements</h2>
                <p>Inventory card for this product.</p>
              </div>
            </div>
            ${table([
              { label: "Date", value: r => text(pick(r, ["movement_date", "MovementDate"], "-")) },
              { label: "Type", value: r => text(pick(r, ["movement_type", "MovementType"], "-")) },
              { label: "Warehouse", value: r => text(pick(r, ["warehouse_code", "WarehouseCode"], "-")) },
              { label: "Document", value: r => text(pick(r, ["document_number", "DocumentNumber"], "-")) },
              { label: "Qty", num: true, value: r => qty(pick(r, ["quantity", "Quantity"], 0)) },
              { label: "Note", value: r => text(pick(r, ["note", "Note"], "")) }
            ], list(movements, 14), "No stock movements.")}
          </div>

          <div class="two-col section">
            <div>
              <div class="section-head">
                <div>
                  <h2>Price History</h2>
                  <p>Sale and purchase price changes.</p>
                </div>
              </div>
              ${table([
                { label: "Type", value: r => text(pick(r, ["price_type", "PriceType"], "-")) },
                { label: "Currency", value: r => text(pick(r, ["currency_code", "Currency"], "-")) },
                { label: "Price", num: true, value: r => money(pick(r, ["price", "Price"], 0)) },
                { label: "From", value: r => text(pick(r, ["valid_from", "ValidFrom"], "-")) },
                { label: "To", value: r => text(pick(r, ["valid_to", "ValidTo"], "Current")) }
              ], list(prices, 10), "No price history.")}
            </div>

            <div>
              <div class="section-head">
                <div>
                  <h2>Norm</h2>
                  <p>Components deducted when this product is sold.</p>
                </div>
              </div>
              ${
                norm
                  ? `
                    <div class="panel" style="margin-bottom:10px">
                      <div class="panel-body">
                        <div class="info-list">
                          <div class="info-item"><span>Norm Code</span><strong>${text(pick(norm, ["normCode", "code"], "-"))}</strong></div>
                          <div class="info-item"><span>Version</span><strong>${text(pick(norm, ["versionNo", "version_no"], "1.0"))}</strong></div>
                          <div class="info-item"><span>Name</span><strong>${text(pick(norm, ["normName", "name"], "-"))}</strong></div>
                          <div class="info-item"><span>Output Qty</span><strong>${qty(pick(norm, ["outputQuantity", "output_quantity"], 1))}</strong></div>
                        </div>
                      </div>
                    </div>
                  `
                  : `<div class="empty">No active norm for this product.</div>`
              }
              ${table([
                { label: "Component", value: r => text(pick(r, ["componentName", "component_name"], "-")) },
                { label: "Code", value: r => text(pick(r, ["componentCode", "component_code"], "-")) },
                { label: "Qty", num: true, value: r => qty(pick(r, ["quantity"], 0)) },
                { label: "Unit", value: r => text(pick(r, ["unitName", "unitCode", "unit"], "-")) }
              ], list(normItems, 12), "No norm components.")}
            </div>
          </div>

          <div class="section">
            <div class="section-head">
              <div>
                <h2>Purchase Lines</h2>
                <p>Recent purchase history for this product.</p>
              </div>
            </div>
            ${table([
              { label: "Date", value: r => text(pick(r, ["document_date", "Date", "date"], "-")) },
              { label: "Document", value: r => text(pick(r, ["document_number", "Number", "documentNumber"], "-")) },
              { label: "Supplier", value: r => text(pick(r, ["supplier", "Supplier", "partner_name"], "-")) },
              { label: "Qty", num: true, value: r => qty(pick(r, ["quantity", "Quantity"], 0)) },
              { label: "Total", num: true, value: r => money(pick(r, ["line_total", "Total", "total", "lineTotal"], 0)) }
            ], list(purchases, 8), "No purchase data.")}
          </div>

          <div class="footer">
            <span>Product report generated by Axon</span>
            <span>${text(model.generatedAt)}</span>
          </div>
        </div>
      </div>
    </div>
  `;
}

appsmith.onReady(render);
appsmith.onModelChange(render);
